-- Mark (do NOT yet delete/edit) the annotations consumed by the flag/
-- completion backfill so they can be hand-verified in Studio first. The
-- ORIGINAL text stays fully visible so the proposed transform can be
-- validated by eye:
--   * fully consumed -> "TODELETE: <original>" (a later migration deletes it)
--   * partly consumed -> "TOEDIT: <original> BECOMES <residual>" (a later
--     migration rewrites the row to just <residual>)
-- Matched by (show slug, set, position) + exact original desc. The actual
-- delete/edit ships as a separate forward migration after verification.

UPDATE "annotations" SET "desc" = 'TODELETE: Ending only.', "updated_at" = now()
WHERE "id" IN (
  SELECT a."id" FROM "annotations" a
  JOIN "tracks" t ON t."id" = a."track_id"
  JOIN "shows" s ON s."id" = t."show_id"
  WHERE s."slug" = '1997-12-28-university-concert-hall-college-park-md' AND t."set" = 'S2' AND t."position" = 6 AND a."desc" = 'Ending only.'
);
